<template>
  <div class="setuplist">
    <van-button color="#7232dd" size="large" @click="back">退出登入</van-button>
    <van-action-sheet
      v-model="show"
      :actions="actions"
      cancel-text="取消"
      close-on-click-action
      @select="onSelect"
    />
  </div>
</template>
<script>
import { mapMutations } from "vuex";

import { Toast } from "vant";
export default {
  name: "setuplist",
  data() {
    return {
      show: false,
      actions: [{ name: "退出登入", color: "#ee0a24" }],
    };
  },
  methods: {
    ...mapMutations(["delToken", "setToken", "deluserid", "dellims_name"]),

    back() {
      this.show = true;
    },
    onSelect(item) {
      this.delToken();
      this.deluserid();
      this.dellims_name();
      this.$router.replace({ name: "index" });
      Toast("退出登入");
    },
  },
};
</script>
<style lang="less">
.setuplist {
  width: 7.5rem;
  height: 13.34rem;
  display: flex;
}
</style>